library(shiny)
library(shinyjs)
library(bslib)
library(shinyvalidate)
library(dplyr)
library(ggplot2)
library(plotly)
library(withr)

results <- readRDS("assets/full_results.rds")

hide.if.id.not.in.colnames <- function(id) {
  if (id %in% colnames(results)) {
    "display:initial;"
  } else {
    "display:none;"
  }
}

required.input.label <- function(label) {
  span(label, span(" *", style = "color:orange;"))
}

ui <- page_sidebar(
  useShinyjs(),
  tags$head(
    tags$style(HTML("
      .section-subtitle {
        font-size: 20px;
      }

      #goButton:active {
        background-color: #1c5e89 !important;
      }

      .hidden {
        height: 0;
        color: transparent;
        width: 0;
        content: '';
      }
      "
    ))
  ),
  sidebar = sidebar(
    span("Disclaimer", class = "section-subtitle"),
    span(
      "This tool is not licensed for medical use, and is designed for non-",
      "commercial, informational purposes only. You should not rely on ",
      "information from this tool as a replacement for medical advice.",
      "If you have or suspect that you have a medical problem, you should ",
      "immediately contact your healthcare provider."
    ),
    span("Licence", class = "section-subtitle"),
    span(
      "Model and tool are available for academic & clinical research ",
      "under MIT license, model parameters available at GITHUB LINK"
    ),
    span("(c) Nova In Silico, 2026")
  ),
  h3("Introduction"),
  span(
    "This calculator applies to patients with Mantle Cell Lymphoma, undergoing",
    " treatment with a Bendamustine-Rituximab chemoimmunotherapy regimen as a ",
    "first line of treatment. The model used for predictions was trained on ",
    "data from the control arm of the SHINE clinical trial (NCT01776840). The ",
    "full control cohort (n = 262) was split into 80% for calibration and 20%",
    " for internal validation."
  ),
  span(
    "This study, carried out under YODA Project 2025-0688, used data obtained ",
    "from the Yale University Open Data Access Project, which has an agreement",
    " with JANSSEN RESEARCH & DEVELOPMENT, L.L.C.. The interpretation and ",
    "reporting of research using this data are solely the responsibility of ",
    "th authors and does not necessarily represent the official views of the ",
    "Yale University Open Data Access Project or JANSSEN RESEARCH & ",
    "DEVELOPMENT, L.L.C.."
  ),
  h3("Calculator"),
  span(
    h3("Patient characteristics", class = "section-subtitle"),
    fluidRow(
      numericInput(
        "AGE",
        required.input.label("Age"),
        min = 60,
        value = 65,
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("OLD")),
      selectizeInput(
        "SEX",
        required.input.label("Patient sex"),
        c("Male", "Female")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("MALE")),
      selectizeInput(
        "ECOG",
        required.input.label("ECOG Performance Status"),
        c("0", "1", "2")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("ECOG.0"))
    ),
    span("Disease characteristics", class = "section-subtitle"),
    fluidRow(
      selectizeInput(
        "STAGE",
        required.input.label("Disease stage"),
        c("II", "III", "IV")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("STAGE.IV")),
      selectizeInput(
        "MIPI.CATEGORY",
        required.input.label("s-MIPI risk category "),
        c("Low risk", "Intermediate risk", "High risk")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames(
        "MIPI.CATEGORY"
      )),
      selectizeInput(
        "SUBTYPE",
        required.input.label("Disease subtype"),
        c("Blastoid", "Non-blastoid")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("BLASTOID")),
      selectizeInput(
        "BULKY",
        required.input.label(
          span(
            "Presence of a bulky lesion",
            span("🛈", title = "Tumor bulk greater than 5cm")
          )
        ),
        c("No", "Yes")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("BULKY")),
      selectizeInput(
        "SPLEEN",
        required.input.label("Spleen involvement"),
        c("No", "Yes")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("SPLEEN")),
      selectizeInput(
        "LIVER",
        required.input.label("Liver involvement"),
        c("No", "Yes")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("SPLEEN")),
      selectizeInput(
        "BONEMARROW",
        required.input.label("Bone marrow involvement"),
        c("No", "Yes")
      ) %>% tagAppendAttributes(style = hide.if.id.not.in.colnames("")),
      selectizeInput(
        "EXTRANODAL",
        required.input.label(
          span(
            "Any extranodal involvement",
            span(
              "🛈",
              title = "Presence of MCL in any other organ than the lymph nodes"
            )
          )
        ),
        c("Yes", "No")
      ) %>% tagAppendAttributes(
        style = hide.if.id.not.in.colnames("EXTRANODAL")
      )
    ),
    textOutput("upToDate") %>% tagAppendAttributes(class = "hidden"),
    textOutput("plotExists") %>% tagAppendAttributes(class = "hidden"),
    conditionalPanel(
      condition = "output.upToDate && output.plotExists",
      actionButton(
        "goButtonDisabled",
        "Compute ",
        style = "
          margin-right: auto;
          background-color: #eee;
          color: white;
          cursor: disabled;
          border-radius: 8px;
        "
      )
    ),
    conditionalPanel(
      condition = "!output.upToDate || !output.plotExists",
      actionButton(
        "goButton",
        "Compute ",
        style = "
          margin-right: auto;
          background-color: #2b8fd1;
          color: white;
          border-radius: 8px;
        "
      )
    ),
    style = "
      padding: 8px 16px 16px 16px;
      border: 1px solid #eee;
      border-radius: 8px;
    "
  ),
  h3("Results"),
  conditionalPanel(
    condition = "output.plotExists",
    plotlyOutput("plot", inline = TRUE) %>%
      div(align = "center")
  )
)

server <- function(input, output) {
  # Util fns
  input.to.df <- function(input) {
    data.frame(
      AGE = input$AGE,
      SEX = input$SEX,
      ECOG = input$ECOG,
      STAGE = input$STAGE,
      MIPI.CATEGORY = input$MIPI.CATEGORY,
      SUBTYPE = input$SUBTYPE,
      BULKY = input$BULKY,
      SPLEEN = input$SPLEEN,
      LIVER = input$LIVER,
      EXTRANODAL = input$EXTRANODAL,
      BONEMARROW = input$BONEMARROW
    )
  }

  # Validation
  update.extranodal <- function(input) {
    if (input$LIVER == "Yes" ||
          input$SPLEEN == "Yes" ||
          input$BONEMARROW == "Yes") {
      disable("EXTRANODAL")
      reset("EXTRANODAL")
    } else {
      enable("EXTRANODAL")
    }
  }
  observeEvent(input$LIVER, update.extranodal(input))
  observeEvent(input$BONEMARROW, update.extranodal(input))
  observeEvent(input$SPLEEN, update.extranodal(input))
  iv <- InputValidator$new()
  iv$add_rule("AGE", sv_between(60, 120))
  iv$enable()

  last.input <- reactiveVal(NULL)
  last.plot <- reactiveVal(NULL)

  # Cache last plot
  observeEvent(
    list(input$goButton),
    {
      last.input(
        input.to.df(input)
      )
      last.plot(
        plot
      )
    },
    ignoreInit = TRUE
  )

  output$upToDate <- reactive({
    identical(
      last.input(),
      input %>%
        input.to.df() %>%
        select(colnames(last.input())[colnames(last.input()) %in% colnames(.)])
    )
  })


  # Plot
  plot <- reactive({
    if (!is.null(last.input())) {
      Sys.sleep(2)
      patient <- data.frame(
        OLD = last.input()$AGE >= 70,
        MALE = last.input()$SEX == "Male",
        ECOG.0 = last.input()$ECOG == "0",
        STAGE.IV = last.input()$STAGE == "IV",
        MIPI.CATEGORY = case_match(last.input()$MIPI.CATEGORY,
          "Low risk" ~ 0,
          "Intermediate risk" ~ 1,
          "High risk" ~ 2
        ),
        BLASTOID = last.input()$SUBTYPE == "Blastoid",
        BULKY = last.input()$BULKY == "Yes",
        SPLEEN = last.input()$SPLEEN == "Yes",
        LIVER = last.input()$LIVER == "Yes",
        EXTRANODAL = last.input()$EXTRANODAL == "Yes",
        BONEMARROW = last.input()$BONEMARROW == "Yes"
      ) %>%
        mutate(across(where(is.logical), as.integer)) %>%
        select(colnames(results)[colnames(results) %in% colnames(.)]) %>%
        merge(results)

      p <- ggplot(data.frame(
        Time = patient$time %>% first / 30.4375,
        PFS = patient$surv %>% first,
        PFSpercent = patient$surv %>% first * 100
      )) +
        geom_step(aes(x = Time,
                      y = PFSpercent,
                      PFS = PFS)) +
        labs(
          title = "Patient-specific survival curve",
          x = "Time (months)",
          y = "Progression-free survival (%)"
        ) +
        lims(
          x = c(0, 120),
          y = c(0, 100)
        )

      with_options(
        list(digits = 2),
        ggplotly(
          p,
          width = 700,
          height = 500,
          tooltip = c("Time", "PFS")
        ) %>%
          config(
            displayModeBar = TRUE,
            displaylogo = FALSE,
            modeBarButtonsToRemove = c(
              "pan2d",
              "select2d",
              "lasso2d",
              "autoScale2d",
              "hoverClosestCartesian",
              "hoverCompareCartesian"
            )
          )
      )
    }
  })
  output$plot <- renderPlotly(plot())
  output$plotExists <- reactive({
    !is.null(plot())
  })
}

shinyApp(
  ui = ui,
  server = server,
)
